<!doctype html><html><body style="font-family:Arial,sans-serif;color:#222;line-height:1.55"><h2>{{ $hotelName }}</h2><p>Dear {{ $booking->customer_name }},</p>@if($booking->booking_status === 'confirmed')<p>Thank you for choosing {{ $hotelName }}. We are pleased to confirm your booking.</p>@else<p>Thank you for your interest in {{ $hotelName }}. Unfortunately, we are unable to approve this booking at this time.</p>@endif<table cellpadding="6"><tr><td><strong>Booking ID</strong></td><td>{{ $booking->booking_reference }}</td></tr><tr><td><strong>Room</strong></td><td>{{ $booking->roomName() }}</td></tr><tr><td><strong>Check-in</strong></td><td>{{ optional($booking->booking_date)->format('F d, Y') }}</td></tr><tr><td><strong>Check-out</strong></td><td>{{ optional($booking->checkout_date)->format('F d, Y') }}</td></tr><tr><td><strong>Guests</strong></td><td>{{ $booking->number_of_guests }}</td></tr><tr><td><strong>Status</strong></td><td>{{ $booking->bookingStatusLabel() }}</td></tr></table><p>For assistance, please contact {{ config('mail.from.address') }}. We look forward to serving you.</p></body></html>
